def tag(local):
    return f"{{{W}}}{local}"

def run_text(run):
    return "".join((t.text or "") for t in run.findall(tag("t")))

def aplicar_color_verde(run):
    rpr = run.find(tag("rPr"))
    if rpr is None:
        rpr = etree.Element(tag("rPr"))
        run.insert(0, rpr)
    for c in rpr.findall(tag("color")):
        rpr.remove(c)
    color_el = etree.SubElement(rpr, tag("color"))
    color_el.set(tag("val"), GREEN)

def set_run_text(run, texto):
    for t in run.findall(tag("t")):
        run.remove(t)
    if not texto:
        return
    t_el = etree.SubElement(run, tag("t"))
    t_el.text = texto
    if texto != texto.strip():
        t_el.set("{http://www.w3.org/XML/1998/namespace}space", "preserve")
